import { Hono } from 'hono';
import { authMiddleware } from '../middleware/auth';

const app = new Hono();

app.use('*', authMiddleware);

app.put('/team/:id', async (c) => {
  const teamId = c.req.param('id');
  const newName = c.req.query('name');

  if (!newName) {
    return c.json({ error: 'New name is required' }, 400);
  }

  // Logic to rename the team
  // For example:
  // await updateTeamName(teamId, newName);

  return c.json({ message: `Team ${teamId} renamed to ${newName}` });
});

export default app;

import { Hono } from 'hono';

const authMiddleware = async (c: any, next: () => Promise<any>) => {
  const isAdmin = c.req.header('Authorization') === 'Bearer adminToken'; // Simplified for example

  if (!isAdmin) {
    return c.json({ error: 'Unauthorized' }, 403);
  }

  await next();
};

export default authMiddleware;

